public int caughtSpeeding(int speed, boolean isBirthday)
{
    if(isBirthday){
        speed -= 5;
    }

    if(speed <= 60){
        return 0;
    } else if(speed <= 80){
        return 1;
    } else{
        return 2;
    }
}

public boolean sameEnds(int[] nums, int n) {
    if (n == 0) {
        return true;
    }

    int length = nums.length;
    if (n > length / 2) {
        return false;
    }

    for (int i = 0; i < n; i++) {
        if (nums[i] != nums[length - n + i]) {
            return false;
        }
    }

    return true;
}

